// Generar los 12 items, uno por signo
const signs = [
  { id: 1,  slug: 'aries',       name: 'Aries',       planet: 'Marte' },
  { id: 2,  slug: 'tauro',       name: 'Tauro',       planet: 'Venus' },
  { id: 3,  slug: 'geminis',     name: 'Géminis',     planet: 'Mercurio' },
  { id: 4,  slug: 'cancer',      name: 'Cáncer',      planet: 'Luna' },
  { id: 5,  slug: 'leo',         name: 'Leo',         planet: 'Sol' },
  { id: 6,  slug: 'virgo',       name: 'Virgo',       planet: 'Mercurio' },
  { id: 7,  slug: 'libra',       name: 'Libra',       planet: 'Venus' },
  { id: 8,  slug: 'escorpio',    name: 'Escorpio',    planet: 'Plutón' },
  { id: 9,  slug: 'sagitario',   name: 'Sagitario',   planet: 'Júpiter' },
  { id: 10, slug: 'capricornio', name: 'Capricornio', planet: 'Saturno' },
  { id: 11, slug: 'acuario',     name: 'Acuario',     planet: 'Urano' },
  { id: 12, slug: 'piscis',      name: 'Piscis',      planet: 'Neptuno' }
];

const areas = ['amor','trabajo','dinero','salud','familia','creatividad','viaje','espiritualidad'];
const today = new Date().toISOString().split('T')[0];

return signs.map(s => ({
  json: {
    ...s,
    date: today,
    area: areas[Math.floor(Math.random() * areas.length)]
  }
}));

