const sign = $('Generar 12 inputs').item.json;
const response = $input.item.json;

try {
  const raw = response.content[0].text;
  const clean = raw.replace(/```json|```/g, '').trim();
  const p = JSON.parse(clean);

  // Validar nivelados dentro de rango (mutation-resistant)
  const clamp = (n) => Math.max(0, Math.min(100, Number(n) || 50));

  return [{
    json: {
      sign_id: sign.id,
      reading_date: sign.date,
      energia_general: String(p.energia_general || '').slice(0, 500),
      area_destacada: sign.area,
      consejo: String(p.consejo || '').slice(0, 240),
      numero_suerte: Math.max(1, Math.min(99, Number(p.numero_suerte) || 7)),
      color_dia: String(p.color_dia || 'dorado').slice(0, 40),
      compatibilidad_dia: Number(p.compatibilidad_dia_id) || null,
      frase_impacto: String(p.frase_impacto || '').slice(0, 120) || null,
      nivel_amor: clamp(p.nivel_amor),
      nivel_fortuna: clamp(p.nivel_fortuna),
      nivel_salud: clamp(p.nivel_salud),
      nivel_trabajo: clamp(p.nivel_trabajo),
      nivel_energia: clamp(p.nivel_energia),
      model_used: 'claude-haiku-4-5-20251001',
      tokens_in: response.usage?.input_tokens || null,
      tokens_out: response.usage?.output_tokens || null,
      generation_cost_usd: ((response.usage?.input_tokens || 0) * 0.8 + (response.usage?.output_tokens || 0) * 4) / 1000000
    }
  }];
} catch (e) {
  return [{ json: { error: e.message, sign_id: sign.id, raw: response.content?.[0]?.text?.slice(0, 200) } }];
}
